"""Unit tests for src/data.py."""import osimport tempfileimport torchimport pytestfrom src.data import FixedDataset, fixed_token_collate, get_dataloader@pytest.fixturedef temp_token_file():    """Create a small token file for testing."""    with tempfile.NamedTemporaryFile(suffix=".pt", delete=False) as f:        tokens = torch.randint(0, 1000, (10000,), dtype=torch.int32)        torch.save({"tokens": tokens}, f.name)        yield f.name    os.unlink(f.name)def test_fixed_dataset_indexing(temp_token_file):    """FixedDataset indexing should be deterministic and correct."""    ds = FixedDataset(temp_token_file, seq_len=128)    assert len(ds) == len(ds.tokens) // (128 + 1)    # Sample 0 and sample 1 should be different.    s0 = ds[0]    s1 = ds[1]    assert not torch.equal(s0["input_ids"], s1["input_ids"])    # Each sample is seq_len + 1 tokens.    assert s0["input_ids"].numel() == 129def test_fixed_dataset_fingerprint_stable(temp_token_file):    """Sample fingerprint should be stable across reloads."""    ds1 = FixedDataset(temp_token_file, seq_len=128)    fp1 = ds1.info.sample_fingerprint    ds2 = FixedDataset(temp_token_file, seq_len=128)    fp2 = ds2.info.sample_fingerprint    assert fp1 == fp2def test_fixed_dataset_vocab_check(temp_token_file):    """Should detect vocab out-of-range."""    with pytest.raises(ValueError, match="out of vocab"):        FixedDataset(temp_token_file, seq_len=128, expected_vocab_size=500)def test_fixed_token_collate():    """Collate should stack and cast to long."""    batch = [{"input_ids": torch.tensor([1, 2, 3], dtype=torch.int32)}]    result = fixed_token_collate(batch)    assert result["input_ids"].dtype == torch.long    assert result["input_ids"].shape == (1, 3)